# Mirrors gecko-trade-agent/bot.py:_build_state_v2_payload. Ported here
# so gecko-mcpay-app's /api/* proxy (GECKO_BOT_URL mode) can demux a
# single snapshot into its 4 Zod-validated endpoints
# (/api/{system,agents,nodes,ledger}). Side-effect-free read-only.
#
# Sprint 24-E (2026-05-29): pnl scope = CURRENT STRATEGY ERA only.
# Per founder framing — pnl shown in the app is "since this strategy
# started." Prior strategy iterations (pre-Setup-C JTO/JUP era) bled
# −$4.20 across configs we've already killed; counting them double-
# penalizes the current bot for old decisions. Setup C cutover at
# 2026-05-28 00:18 UTC is the cohort boundary. Legacy /api/state
# still shows lifetime; only /api/state/v2 (app-facing) is filtered.
# When the next strategy era starts, bump STRATEGY_START_TS.
STRATEGY_START_TS = "2026-05-28T00:18:00+00:00"


def _build_state_v2_payload() -> dict:
    """App-schema-aligned snapshot for gecko-mcpay-app's chrome + views."""
    closed_positions = [p for p in positions if p["status"] == "closed"]
    # Sprint 24-E: filter to current-strategy cohort for the app's pnl.
    strategy_closed = [
        p for p in closed_positions if str(p.get("entry_ts") or "") >= STRATEGY_START_TS
    ]
    total_pnl = sum(p.get("pnl_usd", 0) for p in strategy_closed)
    n_wins = sum(1 for p in strategy_closed if float(p.get("pnl_pct") or 0) >= 0.5)
    n_losses = sum(1 for p in strategy_closed if float(p.get("pnl_pct") or 0) <= -0.5)

    open_positions = [p for p in positions if p["status"] == "open"]
    active_count = len(open_positions)
    if active_count == 0 and INSTRUMENTS:
        active_count = len(INSTRUMENTS)

    system_metrics = {
        "pnl": round(total_pnl, 2),
        "latency": 12,
        "nodeName": "GECKO_BOT_LOCAL",
        "activeAgentsCount": active_count,
        "uptime": "100%",
        "terminalLogs": [
            f"{(e.get('ts') or '')[11:19]} {e.get('msg') or ''}" for e in (signal_feed or [])[-12:]
        ]
        or ["bot ready · awaiting first signal..."],
    }

    agents: list[dict] = []
    for _i, pos in enumerate(open_positions):
        sym = pos.get("symbol") or pos.get("token", "?")[:8]
        pnl_usd = pos.get("pnl_usd") or 0
        pnl_pct = pos.get("pnl_pct") or 0
        sign = "+" if pnl_usd >= 0 else ""
        agents.append(
            {
                "id": f"AGT-{(pos.get('token') or '0000')[:4].upper()}",
                "strategy": f"{sym}-Momentum-Studio",
                "pnl": f"{sign}${abs(pnl_usd):.2f}",
                "uptime": str(pos.get("entry_ts") or "")[:19],
                "volume": f"{(pos.get('amount_usd') or 0) / 1000:.1f}K",
                "roi": f"{sign}{pnl_pct:.1f}%",
                "status": "active" if pnl_pct >= 0 else "warning",
                "sparkline": [25, 45, 12, 32, 28, 55, 30, 42, 18, 52, 65, 40, 58],
                "winRate": f"{(n_wins / max(n_wins + n_losses, 1) * 100):.1f}%",
                "tradesCount": int(n_wins + n_losses),
                "risk": f"{STOP_LOSS_PCT}%",
                "exposure": f"${(pos.get('amount_usd') or 0):.0f}",
                "lane": "paper" if PAPER_TRADE else "real",
            }
        )

    nodes: list[dict] = [
        {
            "id": "RES-GECKO",
            "label": "RES-GECKO",
            "type": "research",
            "x": 410,
            "y": 320,
            "latency": "12ms",
            "status": "ACTIVE",
            "pressure": "42.1%",
            "flowRate": "850MB/s",
            "entropy": "LOW",
            "anomalyScore": 0.1042,
            "trigger": "NORMAL_POLLS",
            "deltaT": "+12ms",
            "recommendation": "LEAVE_OPEN",
        }
    ]
    # Sprint 24-F (2026-05-29) — add TRAP + VAULT terminal nodes after
    # the executor row so the orchestration graph's right-side dashed
    # edges have a destination. Both are real bot components: the
    # circuit-breaker fires on consec_losses; the USDC vault is where
    # realized PnL settles. Without these, SVG paths from each EXEC-*
    # trailed off into empty canvas (founder noticed 2026-05-29 22:35).
    for i, inst in enumerate(INSTRUMENTS[:4]):
        nodes.append(
            {
                "id": f"EXEC-{inst['symbol']}",
                "label": f"EXEC-{inst['symbol']}",
                "type": "executor",
                "x": 680,
                "y": 220 + (i * 100),
                "latency": "8ms",
                "status": "NOMINAL",
            }
        )
    nodes.append(
        {
            "id": "TRAP-CIRCUIT",
            "label": "TRAP-CIRCUIT",
            "type": "trap",
            "x": 900,
            "y": 320,
            "latency": "n/a",
            "status": "NOMINAL",
            "pressure": "0.0%",
            "flowRate": "0B/s",
            "entropy": "LOW",
            "anomalyScore": 0.0042,
            "trigger": "ARMED",
            "deltaT": "0ms",
            "recommendation": "MONITOR",
        }
    )
    nodes.append(
        {
            "id": "VAULT-USDC",
            "label": "VAULT-USDC",
            "type": "terminal",
            "x": 1120,
            "y": 320,
            "latency": "18ms",
            "status": "IDLE",
            "pressure": "2.0%",
            "flowRate": "0B/s",
            "entropy": "LOW",
            "anomalyScore": 0.0011,
            "trigger": "AWAIT_SETTLEMENT",
            "deltaT": "0ms",
            "recommendation": "AWAIT_SWEEP",
        }
    )

    ledger: list[dict] = []
    # Sprint 24-E: ledger also strategy-scoped — same narrative cohort
    # as the pnl number above. The chrome's ledger panel shows the
    # current strategy's trade history, not lifetime.
    for i, pos in enumerate(reversed(strategy_closed[-12:])):
        ts = str(pos.get("exit_ts") or pos.get("entry_ts") or "")[11:19]
        amount_usd = pos.get("pnl_usd") or 0
        sign = "+" if amount_usd >= 0 else ""
        ledger.append(
            {
                "hash": (pos.get("tx_hash") or f"loc{i:04d}...{(pos.get('symbol', '?'))[:4]}")[:12],
                "timestamp": ts or "00:00:00",
                "amount": f"{sign}${abs(amount_usd):.2f}",
                "status": "SWEPT" if amount_usd >= 0 else "ARCHIVED",
            }
        )

    return {
        "system": system_metrics,
        "agents": agents,
        "nodes": nodes,
        "ledger": ledger,
        "meta": {
            "mode": "paper" if PAPER_TRADE else "live",
            "strategy": "jto_breakout_gecko_gated_contest",
            "schema_version": "v2",
            "instruments": [inst["symbol"] for inst in INSTRUMENTS],
        },
    }


# ── Dashboard server ───────────────────────────────────────────────
class _DashHandler(BaseHTTPRequestHandler):
    def log_message(self, *args):
        pass  # silence access logs

    def _send(self, code: int, ctype: str, body: bytes) -> None:
        self.send_response(code)
        self.send_header("Content-Type", ctype)
        self.send_header("Content-Length", str(len(body)))
        self.end_headers()
        self.wfile.write(body)

    def do_GET(self) -> None:
        if self.path == "/api/state/v2":
            # Sprint 24-A (2026-05-29) — app-schema-aligned snapshot.
            # Parallel to /api/state; legacy dashboard keeps working.
            body = json.dumps(_build_state_v2_payload()).encode()
            self._send(200, "application/json", body)
            return
        if self.path == "/api/state":
            closed = [p for p in positions if p["status"] == "closed"]
            # iter-3.x: cumulative stats come from persisted counters
            # (survive reboot). In-session closed[] is still used for
            # the per-position table below.
            # Persisted counters are the source of truth — close_position
            # increments them on every close (paper + live). Fall back to
            # in-session tally only when both are zero (first run before
            # any close happened).
            if realized_pnl_today or wins_today or losses_today:
                total_pnl = realized_pnl_today
                wins = wins_today
                losses = losses_today
            else:
                total_pnl = sum(p.get("pnl_usd", 0) for p in closed)
                wins = sum(1 for p in closed if p.get("pnl_usd", 0) > 0)
                losses = len(closed) - wins
            # Add current_price + threshold prices for open positions so
            # the dashboard surfaces TP / SL / time-stop ETA explicitly.
            state_positions = []
            for p in positions:
                snap = dict(p)
                ep = float(p.get("entry_price") or 0)
                if ep > 0:
                    snap["tp_price"] = ep * (1 + (p.get("tp_pct") or TAKE_PROFIT_PCT) / 100)
                    snap["sl_price"] = ep * (1 - STOP_LOSS_PCT / 100)
                if p["status"] == "open":
                    pd = oc.get_price_info(p["token"])
                    snap["current_price"] = _spot_from_price_response(pd)
                    # Time-stop: 12h from entry (matches the strategy spec).
                    entry_ts = p.get("entry_ts") or ""
                    try:
                        entry_dt = datetime.fromisoformat(entry_ts.replace("Z", "+00:00"))
                        time_stop_dt = (
                            entry_dt.replace(tzinfo=UTC) if entry_dt.tzinfo is None else entry_dt
                        )
                        from datetime import timedelta

                        time_stop_dt = time_stop_dt + timedelta(hours=12)
                        snap["time_stop_eta"] = time_stop_dt.isoformat()
                    except Exception:
                        snap["time_stop_eta"] = None
                state_positions.append(snap)
            payload = {
                "mode": "paper" if PAPER_TRADE else "live",
                # S0-1: surface observation-mode state so the dashboard can
                # render the "entries gated off" banner and the audit prompt
                # sees `strategy_fitness=PASS via observation_mode`.
                "observation_mode": OBSERVATION_MODE,
                "strategy": "jto_breakout_gecko_gated_contest",
                "entry_type": ENTRY_TYPE,
                "sl_pct": STOP_LOSS_PCT,
                "tp_pct": TAKE_PROFIT_PCT,
                "poll_sec": POLL_SEC,
                "wallet": WALLET_ADDRESS[:8] + "..." + WALLET_ADDRESS[-4:]
                if WALLET_ADDRESS
                else "",
                "positions": state_positions,
                "instruments": [
                    {
                        "symbol": inst["symbol"],
                        "mint": inst["mint"],
                        "chain": inst["chain"],
                        **(_LAST_SNAPSHOTS.get(inst["symbol"]) or {}),
                        "last_signal_check": _LAST_SIGNAL_CHECK.get(
                            inst["symbol"], {"breakout": False, "volume_spike": False}
                        ),
                    }
                    for inst in INSTRUMENTS
                ],
                "btc_overlay": {
                    "ok": _BTC_SNAPSHOT.get("ok"),
                    "reason": _BTC_SNAPSHOT.get("reason"),
                    "close": _BTC_SNAPSHOT.get("close"),
                    "ma": _BTC_SNAPSHOT.get("ma"),
                }
                if _BTC_SNAPSHOT
                else None,
                "signal_feed": signal_feed[-50:],
                # Studio Phase 1: latest panel decisions (voices + regime) per
                # instrument, newest-first, for the dashboard's Voices panel.
                "panel": sorted(_LAST_PANEL.values(), key=lambda p: p.get("ts", ""), reverse=True),
                # S41: live Gecko Oracle (fundamentals) verdicts per instrument,
                # newest-first, for the dashboard's Oracle panel.
                "oracle": sorted(_LAST_FUND.values(), key=lambda o: o.get("ts", ""), reverse=True),
                # S41 studio: ADX/RSI/MFI index snapshot per instrument,
                # newest-first, for the dashboard's Indexes panel.
                "indexes": sorted(
                    _LAST_INDEX.values(), key=lambda x: x.get("ts", ""), reverse=True
                ),
                "stats": {
                    "total_trades": (wins + losses) if (wins or losses) else len(closed),
                    "wins": wins,
                    "losses": losses,
                    "pnl_usd": round(total_pnl, 2),
                    "daily_trades": daily_trades,
                    "daily_limit": MAX_DAILY_TRADES,
                    # Sprint 17 (2026-05-28): expose expectancy directly so
                    # any downstream tool (progress script, dashboard, audit)
                    # can read it without re-aggregating positions[].
                    "expectancy_pct": round(
                        sum(
                            p.get("pnl_pct", 0)
                            for p in closed
                            if isinstance(p.get("pnl_pct"), (int, float))
                        )
                        / max(len(closed), 1),
                        3,
                    )
                    if closed
                    else 0.0,
                    "expectancy_usd": round(
                        sum(
                            p.get("pnl_usd", 0)
                            for p in closed
                            if isinstance(p.get("pnl_usd"), (int, float))
                        )
                        / max(len(closed), 1),
                        3,
                    )
                    if closed
                    else 0.0,
                },
                # Sprint 17 (2026-05-28): honest decomposition surface. Per
                # Sprint 5 bot-honesty Fix 1 — per-exit-reason + per-regime +
                # per-symbol breakdown so anyone (dashboard, audit, founder)
                # can see WHICH closes are dragging the mean. Computed lazily
                # here from the closed positions list — no separate counters.
                "honest_decomposition": _compute_honest_decomposition(closed),
                # S0-4: liveness heartbeat surface for the dashboard. The
                # dashboard alarms when (now - still_alive_at) > 2*POLL_SEC.
                "liveness": {
                    "still_alive_at": still_alive_at,
                    "poll_count": poll_count,
                    "stale_threshold_sec": POLL_SEC * 2,
                },
                # S0-5: state-machine snapshot. Dashboard can render the
                # current state + dwell + alert count next to the heartbeat
                # so silent stuck-states become visible at a glance.
                "state_machine": {
                    "current_state": _state_machine.get("current_state"),
                    "entered_at": _state_machine.get("entered_at"),
                    "dwell_sec": round(
                        time.time() - _state_machine.get("entered_at_ts", time.time()), 1
                    ),
                    "slo_sec": _STATE_SLOS_SEC.get(_state_machine.get("current_state")),
                    "alerts_emitted": _state_machine.get("alerts_emitted", 0),
                },
                # S0-7: risk_voice veto rate over the rolling 200-call
                # window. Rate=None means we haven't measured yet (empty
                # window); a low rate (~1-5%) is the EXPECTED healthy state
                # — risk_voice is a safety floor, not a default-bear voice.
                # A persistently zero rate means risk vetoes are never
                # firing (broken voice or impossibly safe inputs); a
                # persistently high rate (>30%) means it's over-vetoing
                # (threshold too tight or the market regime is genuinely
                # adverse). Either signal is now visible.
                "risk_voice_veto_rate": _risk_voice_veto_rate(),
            }
            body = json.dumps(payload).encode()
            self._send(200, "application/json", body)
        else:
            body = DASHBOARD_HTML.encode()
            self._send(200, "text/html", body)


def _start_dashboard() -> None:
    srv = HTTPServer(("", DASHBOARD_PORT), _DashHandler)
    t = threading.Thread(target=srv.serve_forever, daemon=True)
    t.start()
    print(f"📊  Dashboard : http://localhost:{DASHBOARD_PORT}")


# ── Preflight ──────────────────────────────────────────────────────
def preflight() -> bool:
    global WALLET_ADDRESS
    status = oc.wallet_status()
    logged_in = status.get("loggedIn") or status.get("data", {}).get("loggedIn")
    if not logged_in:
        print("❌  Not logged in. Run: onchainos wallet login <email>")
        return False
    addr = oc.get_wallet_address()
    if not addr:
        print("❌  Could not resolve wallet address for chain:", CHAIN)
        return False
    WALLET_ADDRESS = addr
    balances = oc.get_all_balances()
    usdc_bal = next(
        (
            float(b.get("balanceUsd", 0) or 0)
            for b in balances
            if "USDC" in (b.get("symbol") or "").upper()
        ),
        0.0,
    )
    print(f"✅  Wallet : {WALLET_ADDRESS[:8]}...{WALLET_ADDRESS[-4:]}")
    print(f"✅  USDC   : ${usdc_bal:.2f}")
    if usdc_bal < USD_PER_TRADE:
        print(f"⚠️   Low balance: ${usdc_bal:.2f} — need ≥ ${USD_PER_TRADE} to trade")
    if not _usdc_address():
        print(f"⚠️   USDC address not mapped for chain {CHAIN} — live swaps will fail")
    return True


# ── Safety filters ─────────────────────────────────────────────────
def passes_safety(token: str) -> tuple[bool, list[str]]:
    """Run safety filters derived from the spec. Returns (passed, [failed_reasons])."""
    if not SAFETY:
        return True, []
    tags = oc.get_safety_tags(token)
    failed: list[str] = []
    if SAFETY.get("honeypot_check") and tags.honeypot:
        failed.append("HONEYPOT")
    if SAFETY.get("phishing_exclude") and tags.phishing_flagged:
        failed.append("PHISHING")
    if (v := SAFETY.get("lp_locked_min_pct")) and tags.lp_locked_pct < v:
        failed.append(f"LP lock {tags.lp_locked_pct:.0f}%<{v}%")
    if (v := SAFETY.get("buy_tax_max")) and tags.buy_tax_pct > v:
        failed.append(f"buy_tax {tags.buy_tax_pct:.1f}%>{v}%")
    if (v := SAFETY.get("sell_tax_max")) and tags.sell_tax_pct > v:
        failed.append(f"sell_tax {tags.sell_tax_pct:.1f}%>{v}%")
    if (v := SAFETY.get("liquidity_min_usd")) and tags.liquidity_usd < v:
        failed.append(f"liq ${tags.liquidity_usd:.0f}<${v}")
    if (v := SAFETY.get("top_holders_max_pct")) and tags.top_holders_pct > v:
        failed.append(f"top_holders {tags.top_holders_pct:.0f}%>{v}%")
    if (v := SAFETY.get("bundler_max_pct")) and tags.bundler_ratio_pct > v:
        failed.append(f"bundler {tags.bundler_ratio_pct:.0f}%>{v}%")
    if (v := SAFETY.get("dev_holding_max_pct")) and tags.dev_holding_pct > v:
        failed.append(f"dev_hold {tags.dev_holding_pct:.0f}%>{v}%")
    if (v := SAFETY.get("insider_max_pct")) and tags.insider_holding_pct > v:
        failed.append(f"insider {tags.insider_holding_pct:.0f}%>{v}%")
    if (v := SAFETY.get("whale_max_pct")) and tags.whale_max_pct > v:
        failed.append(f"whale {tags.whale_max_pct:.0f}%>{v}%")
    if (v := SAFETY.get("sm_present_min")) and tags.smart_money_count < v:
        failed.append(f"SM count {tags.smart_money_count}<{v}")
    if (v := SAFETY.get("mcap_min_usd")) and tags.mcap_usd < v:
        failed.append(f"mcap ${tags.mcap_usd:.0f}<${v}")
    if (v := SAFETY.get("mcap_max_usd")) and tags.mcap_usd > v:
        failed.append(f"mcap ${tags.mcap_usd:.0f}>${v}")
    return len(failed) == 0, failed


# ── Signal detection ───────────────────────────────────────────────
# Per-instrument kline snapshot, cached for the dashboard.
_LAST_SNAPSHOTS: dict[str, dict] = {}

# Per-instrument last-tick signal-fire booleans, surfaced via /api/state.
_LAST_SIGNAL_CHECK: dict[str, dict[str, bool]] = {}

# ── BTC overlay snapshot (poll-level cache) ────────────────────────
# We fetch BTC candles at most once per tick. The tuple is
# (epoch_ts_of_fetch, {ok, reason, close, ma}). poll_instruments()
# bumps the ts each tick; helper functions read the cached snapshot
# inside the same tick if called more than once.
_BTC_SNAPSHOT_TS: float = 0.0
_BTC_SNAPSHOT: dict[str, object] = {}
# Tick-id sentinel — bumped at the top of every poll_instruments().
# Cached snapshot is reused within a single tick; recomputed otherwise.
_BTC_CURRENT_TICK_ID: int = 0
_BTC_SNAPSHOT_TICK_ID: int = -1

# ── 1h regime cache (Wave-2b multi-TF modulator) ──────────────────────
# Per-instrument 1h candle cache. Refreshed every _1H_REGIME_REFRESH_POLLS
# polls (~6 min at 30s/poll). The regime string feeds coordinator_rules as
# regime_1h to raise the chart floor on TREND-DOWN / CHOP 1h tapes.
# Key: instrument symbol; Value: (regime_str, fetch_ts, poll_count_at_fetch)
_1H_REGIME_CACHE: dict[str, tuple[str, float, int]] = {}
# Refresh 1h candles every N polls (12 × 30s = 6 min — low-freq is intentional;
# 1h regime is a macro read, not a tick read).
_1H_REGIME_REFRESH_POLLS: int = 12
# Global poll counter incremented at the top of each poll_instruments() call.
# Shared with the BTC tick counter (which is a separate concept); this one
# tracks the coarser per-instrument 1h cadence.
_POLL_COUNT: int = 0


def _get_regime_1h(inst: dict) -> str:
    """Return cached 1h regime for *inst*, refreshing every _1H_REGIME_REFRESH_POLLS.

    Fail-open: on any fetch/compute error returns "CHOP" (conservative — raises
    the chart floor but doesn't block trading outright). A None-regime would
    fail-open the other way (no floor raise), which is less safe during an
    outage. We want to err cautiously, so "CHOP" is the right degraded default.
    """
    global _1H_REGIME_CACHE
    sym = inst["symbol"]
    mint = inst["mint"]

    cached = _1H_REGIME_CACHE.get(sym)
    if cached is not None:
        _regime, _ts, _poll = cached
        polls_elapsed = _POLL_COUNT - _poll
        if polls_elapsed < _1H_REGIME_REFRESH_POLLS:
            return _regime

    try:
        # 30 bars of 1H gives 30 hours; need ≥28 for ADX warm-up.
        candles_1h = _get_oc().get_candles(mint, "1H", limit=30)
        if not candles_1h:
            raise ValueError("empty 1h candles")
        regime = _indicators.compute_regime_1h(candles_1h)
    except Exception as exc:
        print(f"[regime_1h] {sym} fetch failed ({type(exc).__name__}: {exc}) — defaulting CHOP")
        regime = "CHOP"

    _1H_REGIME_CACHE[sym] = (regime, time.time(), _POLL_COUNT)
    return regime


def _median(vals: list[float]) -> float:
    if not vals:
        return 0.0
    s = sorted(vals)
    n = len(s)
    mid = n // 2
    if n % 2:
        return float(s[mid])
    return float((s[mid - 1] + s[mid]) / 2.0)


def btc_overlay_passes() -> tuple[bool, str]:
    """Poll-level BTC market filter. Returns (ok, reason).

    Cached per tick via ``_BTC_SNAPSHOT_TICK_ID``: even if called twice in
    the same tick we only fetch once. Fail-open on data error — we'd
    rather take a candidate during an onchainos hiccup than freeze all
    trading silently.
    """
    global _BTC_SNAPSHOT_TS, _BTC_SNAPSHOT, _BTC_SNAPSHOT_TICK_ID
    # iter-3.3 live 2026-05-20: BTC_OVERLAY = None disables the coarse
    # BTC safety belt. Voices remain the real gate (chart_analyst @ 0.85
    # floor + risk + memory). green_candle was binary-cruel on -0.05%
    # red bars during chop, blocking entries on statistical noise.
    if BTC_OVERLAY is None:
        snap = {"ok": True, "reason": "btc_overlay_disabled", "close": 0.0, "ma": 0.0}
        _BTC_SNAPSHOT = snap
        _BTC_SNAPSHOT_TS = time.time()
        _BTC_SNAPSHOT_TICK_ID = _BTC_CURRENT_TICK_ID
        return True, "btc_overlay_disabled"
    if _BTC_SNAPSHOT_TICK_ID == _BTC_CURRENT_TICK_ID and _BTC_SNAPSHOT:
        return bool(_BTC_SNAPSHOT["ok"]), str(_BTC_SNAPSHOT["reason"])

    ma_period = int(BTC_OVERLAY.get("ma_period", 20))
    condition = str(BTC_OVERLAY.get("condition", "above_ma"))

    try:
        candles = _get_oc().get_candles(BTC_WBTC_MINT, "5m", limit=max(ma_period, 24))
    except Exception as exc:  # broad — never let an RPC blip halt the bot
        snap = {
            "ok": True,
            "reason": "btc_data_unavailable_fail_open",
            "close": None,
            "ma": None,
            "error": f"{type(exc).__name__}: {exc}",
        }
        _BTC_SNAPSHOT = snap
        _BTC_SNAPSHOT_TS = time.time()
        _BTC_SNAPSHOT_TICK_ID = _BTC_CURRENT_TICK_ID
        _log("warn", f"[BTC] data fetch raised {type(exc).__name__} — fail open")
        return True, "btc_data_unavailable_fail_open"

    if not candles or len(candles) < ma_period:
        snap = {
            "ok": True,
            "reason": "btc_data_unavailable_fail_open",
            "close": None,
            "ma": None,
        }
        _BTC_SNAPSHOT = snap
        _BTC_SNAPSHOT_TS = time.time()
        _BTC_SNAPSHOT_TICK_ID = _BTC_CURRENT_TICK_ID
        _log("warn", "[BTC] insufficient candle data — fail open")
        return True, "btc_data_unavailable_fail_open"

    closes = [float(c["close"]) for c in candles[-ma_period:]]
    ma = sum(closes) / len(closes)
    current_close = float(candles[-1]["close"])

    if condition == "above_ma":
        ok = current_close >= ma
        reason = "BTC above 20-MA" if ok else f"BTC below {ma_period}-MA"
    elif condition == "green_candle":
        last_open = float(candles[-1]["open"])
        ok = current_close > last_open
        delta_pct = (current_close - last_open) / last_open * 100 if last_open else 0.0
        reason = (
            f"BTC last bar green ({delta_pct:+.2f}%)"
            if ok
            else f"BTC last bar red ({delta_pct:+.2f}%)"
        )
    elif condition == "uptrend":
        # Heuristic: current close above its 8-bar EMA AND 8-bar EMA above
        # its lagged value 4 bars ago. Light, momentum-flavoured.
        if len(closes) < 12:
            ok = True
            reason = "uptrend_insufficient_data_fail_open"
        else:
            recent = closes[-8:]
            ema = recent[0]
            k = 2 / (8 + 1)
            for v in recent[1:]:
                ema = ema * (1 - k) + v * k
            lagged = sum(closes[-12:-4]) / 8
            ok = current_close > ema and ema > lagged
            reason = "BTC in uptrend" if ok else "BTC not in uptrend"
    else:
        # Default policy: unknown conditions pass through. Add support
        # explicitly when starter-coach surfaces new conditions.
        ok = True
        reason = f"unknown_condition_pass:{condition}"

    snap = {"ok": ok, "reason": reason, "close": current_close, "ma": ma}
    _BTC_SNAPSHOT = snap
    _BTC_SNAPSHOT_TS = time.time()
    _BTC_SNAPSHOT_TICK_ID = _BTC_CURRENT_TICK_ID
    return ok, reason


def evaluate_volume_spike(
    inst: dict, candles: list[dict] | None = None
) -> tuple[bool, dict | None]:
    """volume_spike entry primitive.

    Fires when ``volumes[-1] >= VOL_SPIKE_MULTIPLIER * median(volumes[-N:])``
    AND median > 0. The caller MAY pass pre-fetched candles to save a
    network round-trip; if omitted we refetch.
    """
    mint = inst["mint"]
    if candles is None:
        candles = _get_oc().get_candles(mint, TIMEFRAME, limit=max(VOL_SPIKE_AVG_BARS + 1, 24))
    if not candles or len(candles) < 2:
        return False, None
    window = candles[-VOL_SPIKE_AVG_BARS:]
    vols = [float(c.get("volume", 0) or 0) for c in window]
    if not vols:
        return False, None
    last_vol = vols[-1]
    median_vol = _median(vols)
    if median_vol <= 0:
        return False, None
    ratio = last_vol / median_vol
    if last_vol >= VOL_SPIKE_MULTIPLIER * median_vol:
        return True, {
            "signal": "volume_spike",
            "instrument": inst["symbol"],
            "multiplier_observed": round(ratio, 3),
            "last_vol": last_vol,
            "median_vol": median_vol,
        }
    return False, None


def evaluate_breakout(inst: dict) -> dict | None:
    """Evaluate price_breakout on a single instrument's 5m klines.

    Returns a candidate dict ``{token, symbol, signal_data}`` if the
    latest close exceeds the prior ``lookback_bars`` highs by at least
    ``confirm_pct``%; otherwise ``None``. Always refreshes the
    dashboard snapshot for the instrument.
    """
    mint = inst["mint"]
    sym = inst["symbol"]
    lookback = int(ENTRY_PARAMS.get("lookback_bars", 4))
    confirm = float(ENTRY_PARAMS.get("confirm_pct", 0.2))

    _oc = _get_oc()
    candles = _oc.get_candles(mint, TIMEFRAME, limit=max(lookback + 4, 24))
    price_data = _oc.get_price_info(mint)
    spot = _spot_from_price_response(price_data)
    if spot == 0.0 and candles:
        spot = float(candles[-1].get("close") or 0)

    snap = {
        "symbol": sym,
        "mint": mint,
        "spot": spot,
        "bars": len(candles),
        "lookback": lookback,
        "confirm_pct": confirm,
        "delta_pct": None,
        "range_pct": None,
    }
    _LAST_SNAPSHOTS[sym] = snap

    # Item 1 (S41 studio): compute ADX/RSI/MFI from the same candles —
    # no extra network fetch. Warm up silently if warmup not met yet.
    if candles:
        _LAST_INDEX[sym] = _compute_index_snapshot(sym, candles)

    if len(candles) < lookback + 1:
        return None

    # Most-recent candle is last in list per onchainos kline convention.
    recent = candles[-1]
    prior = candles[-(lookback + 1) : -1]
    if not prior:
        return None
    prior_high = max(c["high"] for c in prior)
    prior_low = min(c["low"] for c in prior)
    close = float(recent["close"])
    if prior_high <= 0 or close <= 0:
        return None

    delta_pct = (close - prior_high) / prior_high * 100.0
    range_pct = (prior_high - prior_low) / prior_low * 100.0 if prior_low > 0 else 0.0
    snap["delta_pct"] = round(delta_pct, 3)
    snap["range_pct"] = round(range_pct, 3)

    if _breakout_magnitude_enabled():
        atr_pct = 0.0
        if len(candles) >= 15:
            highs = [float(c["high"]) for c in candles]
            lows = [float(c["low"]) for c in candles]
            closes = [float(c["close"]) for c in candles]
            atr_series = _indicators.atr(highs, lows, closes, 14)
            atr_last = next((a for a in reversed(atr_series) if a is not None), None)
            if atr_last and close > 0:
                atr_pct = atr_last / close * 100.0
        min_move_pct = max(atr_pct, BREAKOUT_MAGNITUDE_MIN_PCT)
        required_close = prior_high * (1 + min_move_pct / 100.0)
        if close < required_close:
            return None

    if delta_pct < confirm:
        return None

    _log(
        "info",
        f"[{sym}] entry signal: breakout up {delta_pct:.2f}% over {lookback} bars",
    )
    return {
        "token": mint,
        "symbol": f"{sym}-USDC",
        "signal_data": {
            "instrument": sym,
            "breakout_pct": round(delta_pct, 3),
            "range_pct": round(range_pct, 3),
            "lookback_bars": lookback,
            "spot_price": spot,
            "close": close,
            "prior_high": prior_high,
        },
    }


def _deterministic_coordinator_gate(sym: str, regime_1h: str | None) -> tuple[str, str | None]:
    """Coordinator path when the LLM panel is disabled (replay / no-key boot).

    Synthetic bullish chart @ 0.90 — gates must decline bad setups; the
    panel is not doing that work in replay. Reads chop/mfi from _LAST_INDEX.
    """
    from voices.base import VoiceOpinion
    from voices.coordinator_rules import coordinator

    idx = _LAST_INDEX.get(sym) or {}
    chop = idx.get("chop")
    mfi = idx.get("mfi")
    regime = idx.get("regime", "unknown")
    if regime == "CHOP":
        regime_verdict, regime_conf = "bearish", 0.70
    else:
        regime_verdict, regime_conf = "bullish", 0.50

    opinions = [
        VoiceOpinion(
            voice_name="chart_analyst",
            verdict="bullish",
            confidence=0.93,
            reasoning="deterministic_replay",
            observations=[],
            raw_response="",
            elapsed_ms=0,
            cost_usd=None,
        ),
        VoiceOpinion(
            voice_name="regime_analyst",
            verdict=regime_verdict,
            confidence=regime_conf,
            reasoning="deterministic_replay",
            observations=[],
            raw_response="",
            elapsed_ms=0,
            cost_usd=None,
        ),
        VoiceOpinion(
            voice_name="risk_voice",
            verdict="abstain",
            confidence=0.0,
            reasoning="deterministic_replay",
            observations=[],
            raw_response="",
            elapsed_ms=0,
            cost_usd=None,
        ),
        VoiceOpinion(
            voice_name="memory_voice",
            verdict="abstain",
            confidence=0.0,
            reasoning="deterministic_replay",
            observations=[],
            raw_response="",
            elapsed_ms=0,
            cost_usd=None,
        ),
    ]
    return coordinator(opinions, regime_1h=regime_1h, chop=chop, mfi=mfi)


def poll_instruments() -> None:
    """Iterate INSTRUMENTS once per poll. MAX_CONCURRENT / daily_trades /
    total_spent_usd guards are checked PER ITERATION so a fill on JTO
    blocks JUP/PYTH in the same tick (global invariants).

    BTC overlay runs ONCE at the top of each tick. price_breakout and
    volume_spike fire in parallel with OR semantics — either firing
    produces a candidate. Voices grade what crosses the bar.

    Wave-2b gates (per-instrument, BEFORE open_position):
      1. 1h regime — low-frequency (refresh every ~6 min). regime_1h is
         stored in _LAST_INDEX and passed to the coordinator via market_state.
      2. net-flow CVD gate — fires ONLY on candidates (after safety). If the
         on-chain net-flow verdict is "distribution", the candidate is blocked
         (distribution spike = sellers hitting bids = falling-knife). Neutral
         and accumulation pass. Fail-open on None.
    """
    global _BTC_CURRENT_TICK_ID, _POLL_COUNT
    _BTC_CURRENT_TICK_ID += 1  # invalidate prior tick's BTC cache
    _POLL_COUNT += 1  # drives 1h regime refresh cadence

    btc_ok, btc_reason = btc_overlay_passes()
    if not btc_ok:
        _log(
            "filter",
            f"[BTC] ✗ {btc_reason} — skipping all instruments this tick",
        )
        return

    for inst in INSTRUMENTS:
        sym = inst["symbol"]
        # GLOBAL guards re-checked every instrument — a fill on the
        # previous iteration must block subsequent ones in this tick.
        if sum(1 for p in positions if p["status"] == "open") >= MAX_CONCURRENT:
            return
        if daily_trades >= MAX_DAILY_TRADES:
            return

        # ── Wave-2b Item 2: fetch/cache 1h regime ─────────────────────
        # Low-freq: refreshes every _1H_REGIME_REFRESH_POLLS polls (~6 min).
        # Fail-open on network error (returns "CHOP" — conservative default).
        regime_1h = _get_regime_1h(inst)

        bo_cand = evaluate_breakout(inst)
        # Patch regime_1h into the index snapshot AFTER evaluate_breakout creates it.
        # evaluate_breakout initialises _LAST_INDEX[sym] with regime_1h=None;
        # we overwrite it here so the dashboard + eval telemetry always see the
        # live value (not None) from this poll onwards.
        if sym in _LAST_INDEX:
            _LAST_INDEX[sym]["regime_1h"] = regime_1h
        # Reuse the candles evaluate_breakout already fetched (via the
        # snapshot side-channel would be cleaner, but a single refetch
        # keeps the call sites independent and avoids hidden coupling
        # between primitives — onchainos has its own short cache).
        vs_fires, vs_signal = evaluate_volume_spike(inst)
        bo_fires = bo_cand is not None

        _LAST_SIGNAL_CHECK[sym] = {
            "breakout": bo_fires,
            "volume_spike": vs_fires,
        }

        # FIX #5 — eval telemetry: one row per symbol per poll for gate evaluation.
        # For no-signal polls the panel never ran, so chart/regime fields will be
        # null — that's correct; the quant needs the full indicator series including
        # quiet polls to evaluate gate calibration over a 5-day paper period.
        if not (bo_fires or vs_fires):
            _log_eval_telemetry(sym, action="no_signal", decline_reason=None)
            continue

        if bo_fires and vs_fires:
            primitive = "breakout+volume"
        elif bo_fires:
            primitive = "breakout"
        else:
            primitive = "volume_spike"

        # Fix 4 — block volume_spike-only when breakout confirmation required.
        if _entry_require_breakout() and primitive == "volume_spike":
            _log("filter", f"[{sym}] ✗ volume_spike alone blocked (require breakout)")
            _log_eval_telemetry(sym, action="decline", decline_reason="volume_spike_alone_blocked")
            _LOGGER.log(
                "candidate_blocked",
                {
                    "symbol": sym,
                    "token": inst["mint"],
                    "primitive": primitive,
                    "regime_1h": regime_1h,
                    "stage": "entry_primitive",
                    "reasons": ["volume_spike_alone_blocked"],
                },
            )
            continue

        # Build a unified signal_data carrying BOTH signal types if both fired.
        signal_data: dict = {"primitive": primitive, "instrument": sym}
        if bo_cand is not None:
            signal_data.update(bo_cand["signal_data"])
        if vs_signal is not None:
            signal_data.update(vs_signal)

        token = bo_cand["token"] if bo_cand else inst["mint"]
        symbol = bo_cand["symbol"] if bo_cand else f"{sym}-USDC"

        ok, failed = passes_safety(token)
        if not ok:
            _log("filter", f"[{sym}] ✗ safety: {', '.join(failed)}")
            # S0-6: counterfactual log — candidate fired but failed pre-gate
            # safety check. Without this row the artifact ledger only sees
            # candidates that REACHED the gate; counterfactual_capture audit
            # category was incomplete by exactly this gap. Includes the
            # failure reasons so the gating-delta analysis can attribute.
            _LOGGER.log(
                "candidate_blocked",
                {
                    "symbol": sym,
                    "token": token,
                    "primitive": primitive,
                    "regime_1h": regime_1h,
                    "stage": "safety",
                    "reasons": failed,
                    "signal_data": signal_data,
                },
            )
            continue

        # ── Wave-2b Item 1: net-flow CVD gate ─────────────────────────
        # Gate runs AFTER safety, BEFORE open_position (and before the panel).
        # Only blocks "distribution" — neutral/accumulation/None pass through.
        # Fail-open on None (network error → don't block a real setup).
        try:
            nf_signal: NetFlowSignal | None = compute_net_flow(token, sym, _get_oc())
        except Exception:
            nf_signal = None  # safety net — must not reach trading loop

        if nf_signal is not None:
            # Update _LAST_INDEX snapshot with live net-flow data.
            if sym in _LAST_INDEX:
                _LAST_INDEX[sym]["net_flow"] = {
                    "net_flow_usd": nf_signal.net_flow_usd,
                    "smart_money_buys": nf_signal.smart_money_buys,
                    "buy_usd": nf_signal.buy_usd,
                    "sell_usd": nf_signal.sell_usd,
                    "trade_count": nf_signal.trade_count,
                }
                _LAST_INDEX[sym]["net_flow_verdict"] = nf_signal.verdict

            if nf_signal.verdict == "distribution":
                _log(
                    "filter",
                    f"[{sym}] ✗ net-flow: distribution "
                    f"(net ${nf_signal.net_flow_usd:+.0f}, SM buys {nf_signal.smart_money_buys}) "
                    f"— decline_reason=distribution_flow",
                )
                _log_eval_telemetry(sym, action="decline", decline_reason="distribution_flow")
                # S0-6: counterfactual log — candidate fired + passed safety
                # but was killed by the net-flow distribution gate. Captures
                # the per-candidate net-flow snapshot so the gating-delta
                # analysis can measure "how often did distribution_flow kill
                # candidates that would have been profitable" — which is the
                # raw substrate the Oracle's calibration needs.
                _LOGGER.log(
                    "candidate_blocked",
                    {
                        "symbol": sym,
                        "token": token,
                        "primitive": primitive,
                        "regime_1h": regime_1h,
                        "stage": "net_flow",
                        "reasons": ["distribution_flow"],
                        "net_flow": {
                            "net_flow_usd": nf_signal.net_flow_usd,
                            "smart_money_buys": nf_signal.smart_money_buys,
                            "verdict": nf_signal.verdict,
                        },
                        "signal_data": signal_data,
                    },
                )
                continue

            _log(
                "info",
                f"[{sym}] net-flow: {nf_signal.verdict} "
                f"(net ${nf_signal.net_flow_usd:+.0f}, SM buys {nf_signal.smart_money_buys})",
            )
        else:
            _log("info", f"[{sym}] net-flow: unavailable — pass-through (fail-open)")

        _log("info", f"[{sym}] ✓ candidate via {primitive} (1h regime: {regime_1h})")
        # Pass regime_1h into signal_data so open_position → market_state → panel
        # coordinator can use it as the multi-TF modulator.
        signal_data["regime_1h"] = regime_1h
        # S0-1: OBSERVATION_MODE gate. When on, every cleared candidate is logged
        # to the counterfactual ledger as the would-be entry, but no order is
        # placed. The voices + Oracle still run inside open_position normally,
        # so the data substrate (panel telemetry, Oracle gating-delta, drift
        # baselines) keeps flowing — only the swap_execute is skipped.
        # Defense-in-depth: open_position() also early-returns under
        # OBSERVATION_MODE in case any other caller path is added later.
        if OBSERVATION_MODE:
            _LOGGER.log(
                "candidate_observation",
                {
                    "token": token,
                    "symbol": symbol,
                    "primitive": primitive,
                    "regime_1h": regime_1h,
                    "signal_data": signal_data,
                    "reason": "OBSERVATION_MODE on — entry skipped, counterfactual logged",
                },
            )
            _log(
                "filter",
                f"[{sym}] ◯ observation-mode: would-enter via {primitive}, logged not-fired",
            )
            _log_eval_telemetry(sym, action="decline", decline_reason="observation_mode")
            continue
        if _LOCAL_PANEL is None:
            dc_action, dc_reason = _deterministic_coordinator_gate(sym, regime_1h)
            if dc_action != "act":
                _log("filter", f"[{sym}] ✗ coordinator (deterministic): {dc_reason}")
                _log_eval_telemetry(sym, action="decline", decline_reason=dc_reason)
                continue
        open_position(token, symbol, signal_data)


# ── Position lifecycle ─────────────────────────────────────────────
def open_position(token: str, symbol_str: str, signal_data: dict) -> None:
    global daily_trades, total_spent_usd
    # S0-1 defense-in-depth: if any future call path bypasses the
    # poll_instruments OBSERVATION_MODE gate, this early-return ensures
    # no entry leaks through. The candidate is still logged so the
    # counterfactual stays complete.
    if OBSERVATION_MODE:
        _LOGGER.log(
            "candidate_observation",
            {
                "token": token,
                "symbol": symbol_str,
                "signal_data": signal_data,
                "reason": "OBSERVATION_MODE on — defensive early-return inside open_position()",
            },
        )
        return
    if daily_trades >= MAX_DAILY_TRADES:
        return
    if sum(1 for p in positions if p["status"] == "open") >= MAX_CONCURRENT:
        return
    if any(p["token"] == token and p["status"] == "open" for p in positions):
        return  # already in this token
    if not PAPER_TRADE and total_spent_usd + USD_PER_TRADE > MAX_BUDGET_USD:
        _log(
            "guard",
            f"[BUDGET CAP] ${total_spent_usd:.2f} spent — max budget ${MAX_BUDGET_USD} reached",
        )
        return

    price_data = _get_oc().get_price_info(token)
    entry_price = _spot_from_price_response(price_data)
    if entry_price <= 0:
        print(f"[SKIP] No price for {symbol_str or token[:12]}")
        return

    # ── Gecko wrap: circuit-breaker check, then verdict-gated entry ──
    paused, reason = _BREAKER.check()
    if paused:
        _log("guard", f"[BREAKER] {reason}")
        _LOGGER.log("breaker_trip", {"token": token, "reason": reason})
        return

    instrument = symbol_str.split("-")[0] if symbol_str else token[:8]

    # Fetch fresh candles for chart_analyst — the voice's load-bearing
    # input. Without this, chart_analyst sees market_state["candles"]
    # as empty and abstains with "Fewer than 24 bars provided" — which
    # silently bottlenecks every panel decision into chart_below_threshold.
    # ~50ms call; only fires on candidate entries (not every poll).
    try:
        ms_candles = _get_oc().get_candles(token, TIMEFRAME, limit=30)
    except Exception as exc:
        print(f"[market_state] candle fetch failed for {symbol_str}: {exc}")
        ms_candles = []

    # Compute deltas + range from the fresh candles. The signal_data dict
    # doesn't carry these (evaluate_breakout / evaluate_volume_spike don't
    # populate priceChange24h / range24h / volume24h), so reading from it
    # always returned 0.0 — chart_analyst then read "range 0.00%" and
    # abstained as "range-bound chop." Compute authoritatively from candles.
    chg_24h, chg_1h, range_24h, vol_total = 0.0, 0.0, 0.0, 0.0
    if ms_candles and len(ms_candles) >= 2:
        closes = [float(c.get("close") or c.get("c") or 0) for c in ms_candles]
        highs = [float(c.get("high") or c.get("h") or 0) for c in ms_candles]
        lows = [float(c.get("low") or c.get("l") or 0) for c in ms_candles]
        vols = [float(c.get("volume") or c.get("vol") or 0) for c in ms_candles]
        anchor = closes[0] if closes and closes[0] > 0 else 0
        spot_close = closes[-1] if closes else 0
        if anchor > 0:
            chg_24h = (spot_close - anchor) / anchor * 100
            range_24h = (max(highs) - min(lows)) / anchor * 100
        if len(closes) >= 12 and closes[-12] > 0:
            chg_1h = (spot_close - closes[-12]) / closes[-12] * 100
        vol_total = sum(vols)

    market_state = {
        "instrument": instrument,
        "spot_price": entry_price,
        "change_24h_pct": chg_24h,
        "change_1h_pct": chg_1h,
        "range_24h_pct": range_24h,
        "volume_24h": vol_total,
        # chart_analyst input — the actual OHLCV bars the voice grades.
        "candles": ms_candles,
        # risk_voice deterministic-only context (post-2026-05-20 patch):
        "open_positions": sum(1 for p in positions if p["status"] == "open"),
        "daily_trades": daily_trades,
        "total_spent_usd": total_spent_usd,
        "hourly_pnl_delta": 0.0,
        "max_daily_trades": MAX_DAILY_TRADES,
        "max_budget_usd": MAX_BUDGET_USD,
        # Wave-2b: 1h regime passed through from poll_instruments() via
        # signal_data so the panel coordinator can use the multi-TF modulator
        # without a second network call. None = unknown = fail-open.
        "regime_1h": signal_data.get("regime_1h"),
    }

    # ── Local-lab panel (runs BEFORE the Gecko shadow gate) ─────────
    # Lazy `is not None` lets the bot run before ai-ml-engineer's
    # voices land. Once they do, a voice-bootstrap module wires the
    # panel in and this branch starts firing. The local panel is
    # advisory + observed via local_memory.jsonl; the Gecko shadow
    # gate still runs below and is the only thing that touches the
    # artifact-log ledger surface.
    if _LOCAL_PANEL is not None:
        local_decision = asyncio.run(_LOCAL_PANEL.run(market_state))
        # S0-7: feed the panel's risk_voice opinion into the rolling
        # veto-rate window so the dashboard can render an honest
        # "vetoed 3/127 calls (2.4%)" metric instead of an opaque
        # constant-confidence reading.
        _record_risk_voice(local_decision.voice_opinions)
        # Studio Phase 1: capture the per-voice votes + the coordinator's
        # chosen rule for the live dashboard. Keyed by instrument; the
        # dashboard shows the most-recent decision across the universe.
        _regime = next(
            (o for o in local_decision.voice_opinions if o.voice_name == "regime_analyst"),
            None,
        )
        _LAST_PANEL[instrument] = {
            "ts": datetime.now(UTC).isoformat(),
            "instrument": instrument,
            "action": local_decision.action,
            "rule": local_decision.coordinator_rule_fired,
            "regime": (
                "TREND"
                if _regime and _regime.verdict == "bullish"
                else "CHOP"
                if _regime and _regime.verdict == "bearish"
                else "transitional"
                if _regime and _regime.verdict == "neutral"
                else "?"
            ),
            "voices": [
                {
                    "name": o.voice_name,
                    "verdict": o.verdict,
                    "confidence": round(o.confidence, 2),
                    # Item 2: full reasoning for chart_analyst (the bot's actual
                    # read); 300 chars for other voices. Dashboard renders it.
                    "reasoning": (o.reasoning or "")[
                        : (300 if o.voice_name == "chart_analyst" else 200)
                    ],
                }
                for o in local_decision.voice_opinions
            ],
        }
        # Sprint 24-C (2026-05-29) — per-voice attribution on the artifact
        # event. Strategist review of 2026-05-29 surfaced that voice_count
        # alone makes every fire entry look identical (e.g. 2B/1S/0N/1A),
        # so strategist_voice agree/dissent is invisible from disk. Adding
        # the full {name, verdict, confidence} list per voice unblocks the
        # "is the panel calibrated" autopsy without changing any gate.
        _voice_attribution = [
            {
                "name": o.voice_name,
                "verdict": o.verdict,
                "confidence": round(o.confidence, 3),
            }
            for o in local_decision.voice_opinions
        ]
        # Sprint 24-J (2026-05-30) — SHADOW indicator snapshot. Logged
        # only, not enforced. After ≥7 days of data, mine via
        # scripts/analysis/mfi_shadow_review.py to test the hypothesis
        # "MFI<30 entries are worse than MFI≥30 entries." If signal
        # supports it (n≥15/bucket, Mann-Whitney p<0.05, bucket mean
        # pnl meaningfully lower), promote the gate. Zero behavior
        # change today — pure observation.
        _ix_snapshot = _LAST_INDEX.get(instrument, {}) or {}
        _mfi_at_decision = _ix_snapshot.get("mfi")
        _rsi_at_decision = _ix_snapshot.get("rsi")
        _adx_at_decision = _ix_snapshot.get("adx")
        _chop_at_decision = _ix_snapshot.get("chop")
        _shadow_indicators = {
            "mfi": _mfi_at_decision,
            "rsi": _rsi_at_decision,
            "adx": _adx_at_decision,
            "chop": _chop_at_decision,
        }
        _shadow_gates = {
            "mfi_below_30": _mfi_at_decision is not None and _mfi_at_decision < 30,
            "mfi_below_20": _mfi_at_decision is not None and _mfi_at_decision < 20,
            "rsi_above_70": _rsi_at_decision is not None and _rsi_at_decision > 70,
            "adx_below_20": _adx_at_decision is not None and _adx_at_decision < 20,
        }
        _LOGGER.log(
            "local_panel",
            {
                "instrument": instrument,
                "action": local_decision.action,
                "reason": local_decision.reason,
                "coordinator_rule_fired": local_decision.coordinator_rule_fired,
                "voice_count": len(local_decision.voice_opinions),
                "voices": _voice_attribution,
                "indicators": _shadow_indicators,
                "shadow_gates": _shadow_gates,
                "total_elapsed_ms": local_decision.total_elapsed_ms,
                "total_cost_usd": local_decision.total_cost_usd,
            },
            decision_id=local_decision.decision_id,
        )
        # FIX #5 — eval telemetry for candidate polls (panel ran).
        # _LAST_PANEL[instrument] was just updated above, so all fields are fresh.
        _log_eval_telemetry(
            instrument,
            action=local_decision.action,
            decline_reason=local_decision.reason if local_decision.action != "act" else None,
        )
        if local_decision.action != "act":
            _log("filter", f"[LOCAL] ✗ {local_decision.reason}")
            return

    # ── Gecko Oracle: cached PRD fundamentals verdict (s40-lab-#7, s41) ──
    # The slow, corpus-grounded value-investor read, cached per-instrument.
    # Logged as a side-note AND used as a SOFT gate (s41): a "pass" verdict
    # (oracle says no on fundamentals) blocks the entry; "defer"/"act"/no-
    # verdict do NOT block — the slow lens only vetoes clearly-bad
    # fundamentals, so momentum scalps still flow. Cache may be empty
    # (preload failed, degraded mode, unknown instrument) — then we proceed.
    fund_verdict = _FUNDAMENTALS.get_for_instrument(instrument)
    fund_decision_id: str | None = None
    if fund_verdict is not None:
        cache_age_s = (datetime.now(UTC) - fund_verdict.ts).total_seconds()
        _LAST_FUND[instrument] = _fund_snapshot(fund_verdict)
        fund_decision_id = _LOGGER.log(
            "fundamentals_check",
            {
                "instrument": instrument,
                "verdict": fund_verdict.verdict,
                "confidence": fund_verdict.confidence,
                "key_drivers": fund_verdict.key_drivers,
                "blocker_questions": fund_verdict.blocker_questions,
                "citations_count": fund_verdict.citations_count,
                "cache_age_s": cache_age_s,
                "protocol": fund_verdict.protocol,
            },
            decision_id=local_decision.decision_id if _LOCAL_PANEL is not None else None,
        )
        _log(
            "info",
            f"[ORACLE] {instrument}: {fund_verdict.verdict}@{fund_verdict.confidence:.2f} "
            f"({fund_verdict.citations_count} cites, age {cache_age_s / 60:.0f}m)",
        )
        # Sprint 20 #3 — render structured dissent as a one-line terminal
        # output. Marina sees WHICH voice opposed + WHAT it said before the
        # bot acts on the verdict. Emits even on PASS verdicts so the
        # adversarial layer is visible regardless of the decision. Silent
        # when the L1 panel was unanimous (consensus IS the signal).
        _dissent_entries = getattr(fund_verdict, "dissent", []) or []
        if _dissent_entries:
            _dissent_summary = " · ".join(
                f'{d.get("voice", "?")} — "{d.get("verbatim", "?")}"'
                for d in _dissent_entries[:3]
                if isinstance(d, dict)
            )
            _log(
                "info",
                f"[ORACLE] {instrument}: Dissent ({len(_dissent_entries)}): {_dissent_summary}",
            )
        # Oracle soft gate (s41): only a GROUNDED verdict gets a vote. Per the
        # founder principle "approve or decline only with information", an
        # ungrounded verdict (< ORACLE_GROUNDING_MIN_CITES citations) is treated
        # as ABSTAIN — the oracle had no corpus to stand on, so we avoid the
        # opinion and let the local panel decision stand. A grounded "pass"
        # blocks the entry; grounded "act"/"defer" allow it.
        if fund_verdict.citations_count < ORACLE_GROUNDING_MIN_CITES:
            _log(
                "info",
                f"[ORACLE] {instrument}: ungrounded "
                f"({fund_verdict.citations_count} cites < {ORACLE_GROUNDING_MIN_CITES}) "
                f"— abstaining, no gate",
            )
        elif fund_verdict.verdict == "pass":
            _LOGGER.log(
                "oracle_reject",
                {
                    "instrument": instrument,
                    "verdict": fund_verdict.verdict,
                    "confidence": fund_verdict.confidence,
                    "citations_count": fund_verdict.citations_count,
                },
                decision_id=fund_decision_id,
            )
            _log(
                "filter",
                f"[ORACLE] ✗ {instrument}: GROUNDED pass "
                f"({fund_verdict.citations_count} cites) — entry blocked",
            )
            return
    else:
        _log("info", f"[ORACLE] {instrument}: no cached verdict (degraded)")

    ts = datetime.utcnow().isoformat()
    # Adaptive TP (s60): scale TP to volatility — TP% = clamp(1.5 x ATR%, 0.5, 3.0).
    # Validated by scripts/calibration/adaptive_tp_validation.py: beats fixed-2% CI-clean
    # on win-rate (44.6%->55.5%) + drawdown (exit hygiene, not alpha). Per-position; falls
    # back to TAKE_PROFIT_PCT if candles/ATR unavailable (and for older positions w/o tp_pct).
    adaptive_tp_pct = float(TAKE_PROFIT_PCT)
    try:
        if ms_candles and len(ms_candles) >= 16 and entry_price > 0:
            _atr_series = _indicators.atr(highs, lows, closes, 14)
            _atr_last = next((a for a in reversed(_atr_series) if a is not None), None)
            if _atr_last:
                adaptive_tp_pct = max(0.5, min(3.0, 1.5 * (_atr_last / entry_price * 100.0)))
    except Exception:  # never let TP sizing break entry; fall back to fixed TP
        adaptive_tp_pct = float(TAKE_PROFIT_PCT)
    # Sprint 24-J (2026-05-30) — entry-time indicator snapshot stamped
    # on the position so post-close analysis can correlate entry-MFI/RSI/
    # ADX/CHOP with realized pnl. Paired with the shadow_gates logging
    # at decision time in the local_panel artifact event.
    # _LAST_INDEX is keyed by bare symbol ("PYTH"), not "PYTH-USDC".
    _entry_ix = _LAST_INDEX.get(symbol_str.split("-")[0], {}) or {}
    pos = {
        "token": token,
        "symbol": symbol_str,
        "entry_price": entry_price,
        "usd": USD_PER_TRADE,
        "entry_ts": ts,
        "status": "open",
        "peak_price": entry_price,
        "signal_data": signal_data,
        "mode": "paper",
        "fundamentals_decision_id": fund_decision_id,
        "tp_pct": round(adaptive_tp_pct, 4),
        "entry_indicators": {
            "mfi": _entry_ix.get("mfi"),
            "rsi": _entry_ix.get("rsi"),
            "adx": _entry_ix.get("adx"),
            "chop": _entry_ix.get("chop"),
            "bb_width": _entry_ix.get("bb_width"),
            "regime_5m": _entry_ix.get("regime"),
            "regime_1h": _entry_ix.get("regime_1h"),
        },
    }

    # ── Decision-record store (s43): record this act-decision ──────────
    # Wrapped so a recorder fault can NEVER break the trading loop. Only
    # fires when the recorder armed (skipped under pytest / on init failure).
    if _RECORDER is not None and _RUN_ID is not None:
        try:
            snap = dict(_LAST_INDEX.get(instrument) or {})
            snap["range_24h_pct"] = market_state.get("range_24h_pct")
            # adx_slope needs an ADX series — recompute best-effort from the
            # fresh candles; None if insufficient bars.
            adx_series: list[float | None] = []
            try:
                if ms_candles and len(ms_candles) >= 2:
                    _h = [float(c.get("high") or c.get("h") or 0) for c in ms_candles]
                    _l = [float(c.get("low") or c.get("l") or 0) for c in ms_candles]
                    _c = [float(c.get("close") or c.get("c") or 0) for c in ms_candles]
                    adx_series, _, _ = _indicators.adx_full(_h, _l, _c)
            except Exception:  # slope is optional telemetry — never block the entry
                adx_series = []
            snap["adx_slope"] = _indicators.adx_slope(adx_series) if adx_series else None
            snap["adx_distance"] = _indicators.adx_distance(snap.get("adx"))
            snap["chop_distance"] = _indicators.chop_distance(snap.get("chop"))
            _panel_voices = (
                [
                    {
                        "name": o.voice_name,
                        "verdict": o.verdict,
                        "confidence": o.confidence,
                        "reasoning": (o.reasoning or "")[:300],
                    }
                    for o in local_decision.voice_opinions
                ]
                if _LOCAL_PANEL is not None
                else []
            )
            _oracle_dict = (
                {
                    "verdict": fund_verdict.verdict,
                    "confidence": fund_verdict.confidence,
                    "citations": fund_verdict.citations_count,
                    "grounded": fund_verdict.citations_count >= ORACLE_GROUNDING_MIN_CITES,
                }
                if fund_verdict is not None
                else None
            )
            _coordinator = (
                {
                    "action": local_decision.action,
                    "rule": local_decision.coordinator_rule_fired,
                }
                if _LOCAL_PANEL is not None
                else {"action": "act", "rule": "no_local_panel"}
            )
            _did = _RECORDER.record(
                build_decision_doc(
                    _RUN_ID,
                    instrument,
                    snap,
                    {"fired": True, "type": ENTRY_TYPE},
                    _panel_voices,
                    _oracle_dict,
                    _coordinator,
                )
            )
            pos["decision_id"] = _did  # carry the link to the outcome on close
        except Exception as exc:  # recorder must never break the trading loop
            print(f"[decision-store] record skipped: {type(exc).__name__}: {exc}")

    if PAPER_TRADE:
        _log(
            "buy",
            f"[PAPER] BUY {symbol_str or token[:12]} @ ${entry_price:.6f} | ${USD_PER_TRADE} | SL -{STOP_LOSS_PCT}%",
        )
    else:
        usdc = _usdc_address()
        if not usdc:
            _log("error", f"[ERROR] USDC address not mapped for {CHAIN}")
            return
        result = oc.swap_execute(usdc, token, str(USD_PER_TRADE), WALLET_ADDRESS)
        if not result.ok:
            _log("error", f"[ERROR] Swap failed: {result.error}")
            return
        pos["mode"] = "live"
        pos["tx_hash"] = result.tx_hash
        total_spent_usd += USD_PER_TRADE
        _log(
            "buy",
            f"[LIVE] BUY {symbol_str} @ ${entry_price:.6f} | tx: {result.tx_hash[:16]}... | total spent ${total_spent_usd:.2f}/${MAX_BUDGET_USD}",
        )

    positions.append(pos)
    daily_trades += 1
    _LOGGER.log(
        "position_open",
        {
            "token": token,
            "symbol": symbol_str,
            "entry_price": entry_price,
            "usd": USD_PER_TRADE,
            "mode": pos["mode"],
        },
        decision_id=fund_decision_id,
    )
    _persist_state()


def close_position(pos: dict, reason: str, current_price: float) -> None:
    global consec_losses, realized_pnl_today, wins_today, losses_today, total_spent_usd
    ep = pos["entry_price"]
    cost_usd = float(pos.get("usd") or 0)
    # Oracle-price estimate — used for PAPER mode and as a pre-swap log hint.
    est_pnl_pct = (current_price - ep) / ep * 100 if ep else 0.0
    est_pnl_usd = cost_usd * est_pnl_pct / 100

    # iter-3.7 live 2026-05-20: for LIVE positions, execute the exit swap
    # FIRST and compute realized PnL from the ACTUAL USDC received
    # (swap.to_amount_raw), not the oracle price. The oracle can flash a
    # spiky tick (WIF flashed +6.2% but really filled +0.45%); booking the
    # oracle reading inflated dashboard PnL ~3.5x vs the real wallet.
    pnl_usd = est_pnl_usd
    pnl_pct = est_pnl_pct
    exit_tx = ""
    if not PAPER_TRADE and pos.get("mode") == "live":
        usdc = _usdc_address()
        bal = oc.get_token_balance(pos["token"])
        if bal > 0 and usdc:
            result = oc.swap_execute(pos["token"], usdc, str(bal), WALLET_ADDRESS)
            if result.ok:
                exit_tx = result.tx_hash
                # Real USDC received = to_amount_raw / 10^to_decimals.
                try:
                    if result.to_amount_raw and result.to_decimals:
                        usdc_received = float(result.to_amount_raw) / (10**result.to_decimals)
                        pnl_usd = round(usdc_received - cost_usd, 4)
                        pnl_pct = round(pnl_usd / cost_usd * 100, 2) if cost_usd else 0.0
                    else:
                        # Swap ok but no amount returned — fall back to oracle
                        # estimate and flag it for the audit log.
                        print("   [WARN] swap ok but to_amount missing — using oracle estimate")
                except (TypeError, ValueError, ZeroDivisionError):
                    print("   [WARN] could not parse swap fill — using oracle estimate")
                print(f"   exit tx: {exit_tx[:16]}... | real fill PnL ${pnl_usd:+.2f}")
            else:
                # Exit swap FAILED — do NOT mark the position closed. Leave it
                # open so the next monitor tick retries. Booking a close here
                # would strand the token in the wallet (the PYTH bug).
                print(
                    f"   [ERROR] Exit swap failed: {result.error} — position stays OPEN for retry"
                )
                return

    pos.update(
        {
            "status": "closed",
            "exit_ts": datetime.utcnow().isoformat(),
            "exit_price": current_price,
            "exit_reason": reason,
            "pnl_pct": round(pnl_pct, 2),
            "pnl_usd": round(pnl_usd, 2),
            "exit_tx": exit_tx,
        }
    )

    # ── Decision-record store (s43): link the realized outcome ─────────
    # Wrapped so a recorder fault can NEVER break the close path. The
    # decision_id was stored on the position dict at open_position time.
    if _RECORDER is not None and pos.get("decision_id"):
        try:
            duration_min: float | None = None
            try:
                _ent = datetime.fromisoformat(pos["entry_ts"])
                _ext = datetime.fromisoformat(pos["exit_ts"])
                duration_min = round((_ext - _ent).total_seconds() / 60.0, 2)
            except Exception:  # duration is optional telemetry — never block the close
                duration_min = None
            # peak_pct from the tracked peak_price vs entry (no peak_pct local).
            peak_pct: float | None = None
            _peak_price = pos.get("peak_price")
            if _peak_price and ep:
                peak_pct = round((_peak_price - ep) / ep * 100, 2)
            _RECORDER.attach_outcome(
                pos["decision_id"],
                Outcome(
                    pnl_pct=round(pnl_pct, 2),
                    pnl_usd=round(pnl_usd, 2),
                    exit_reason=reason,
                    duration_min=duration_min,
                    entry_price=ep,
                    exit_price=current_price,
                    peak_pct=peak_pct,
                ),
            )
        except Exception as exc:  # recorder must never break the close path
            print(f"[decision-store] attach_outcome skipped: {type(exc).__name__}: {exc}")

    consec_losses = consec_losses + 1 if pnl_pct < 0 else 0
    # iter-3.x 2026-05-20: accumulate into persisted counters so the
    # dashboard PnL tile survives a bot reboot.
    realized_pnl_today = round(realized_pnl_today + pnl_usd, 4)
    if pnl_usd > 0:
        wins_today += 1
    elif pnl_usd < 0:
        losses_today += 1
    # iter-3.7: free the budget the closed position was holding so new
    # entries can fire (was the stuck-at-$90 budget-cap bug).
    if pos.get("mode") == "live":
        total_spent_usd = round(max(0.0, total_spent_usd - cost_usd), 4)
    icon = "📗" if pnl_pct >= 0 else "📕"
    _log(
        "sell",
        f"{icon} CLOSE {pos['symbol'] or pos['token'][:12]} | {reason} | {pnl_pct:+.1f}% | ${pnl_usd:+.2f}",
    )

    # ── Gecko wrap: feed realized PnL into the breaker + ledger ─────
    _BREAKER.record_pnl_delta(float(pnl_usd))
    _LOGGER.log(
        "position_close",
        {
            "token": pos["token"],
            "symbol": pos.get("symbol"),
            "exit_reason": reason,
            "pnl_pct": round(pnl_pct, 2),
            "pnl_usd": round(pnl_usd, 2),
            "exit_tx": exit_tx,
        },
        decision_id=pos.get("gate_decision_id"),
    )
    _persist_state()


# ── Per-poll telemetry (iter-3.8, 2026-05-21) ──────────────────────
# Append one row per open position per poll to poll_telemetry_YYYYMMDD.jsonl.
# This is the DATA FOUNDATION for the data-driven stall detector (v2): the
# quant flagged that we currently store no per-poll price series, so no stall
# threshold can ever be validated. Schema maps 1:1 to a future Mongo
# collection (lab-first, transplant to PRD per local_lab_strategy). The
# return-series alone supports the highest-merit v2 signal (autocorrelation
# of returns: mean-reverting ⇒ stall, persistent ⇒ pause) — no volume needed.
_TELEMETRY_PATH = _STATE_BASE / f"poll_telemetry_{datetime.now(UTC).strftime('%Y%m%d')}.jsonl"

# Per-poll per-symbol evaluation telemetry for the quant gate evaluation.
# One JSONL row per symbol per poll: indicators + panel decision + action.
# Respects GECKO_STATE_DIR like all other state files. Never crashes the loop.
_EVAL_TELEMETRY_PATH = _STATE_BASE / f"eval_telemetry_{datetime.now(UTC).strftime('%Y%m%d')}.jsonl"


def _log_telemetry(row: dict) -> None:
    """Best-effort append of a per-poll telemetry row. Never raises into the
    poll loop — telemetry failure must not halt trading."""
    try:
        with open(_TELEMETRY_PATH, "a", encoding="utf-8") as f:
            f.write(json.dumps(row) + "\n")
    except OSError:
        pass


def _log_eval_telemetry(sym: str, action: str | None, decline_reason: str | None) -> None:
    """Append one eval-telemetry row for sym to eval_telemetry_YYYYMMDD.jsonl.

    Pulls indicator snapshot from _LAST_INDEX[sym] and the most-recent
    panel decision from _LAST_PANEL[sym] (if present). All fields are
    best-effort: missing values write null. Never raises — instrumentation
    must never break trading.
    """
    try:
        idx = _LAST_INDEX.get(sym) or {}
        panel = _LAST_PANEL.get(sym) or {}
        # Extract regime + chart voice from the panel's voices list
        voices = panel.get("voices") or []
        regime_v = next((v for v in voices if v.get("name") == "regime_analyst"), {})
        chart_v = next((v for v in voices if v.get("name") == "chart_analyst"), {})
        row = {
            "ts": datetime.now(UTC).isoformat(),
            "symbol": sym,
            "price": idx.get("price"),
            "adx": idx.get("adx"),
            "plus_di": idx.get("plus_di"),
            "minus_di": idx.get("minus_di"),
            "rsi": idx.get("rsi"),
            "mfi": idx.get("mfi"),
            "bb_width": idx.get("bb_width"),
            "chop": idx.get("chop"),
            # range_24h_pct is not in _LAST_INDEX — best effort from snapshot
            "range_24h_pct": _LAST_SNAPSHOTS.get(sym, {}).get("range_pct"),
            "regime": panel.get("regime"),
            "chart_verdict": chart_v.get("verdict"),
            "chart_conf": chart_v.get("confidence"),
            "action": action,
            "decline_reason": decline_reason,
            # Wave-2b fields — None when not yet computed this poll.
            "regime_1h": idx.get("regime_1h"),
            "net_flow_verdict": idx.get("net_flow_verdict"),
            "net_flow_usd": (idx.get("net_flow") or {}).get("net_flow_usd"),
            "smart_money_buys": (idx.get("net_flow") or {}).get("smart_money_buys"),
        }
        with open(_EVAL_TELEMETRY_PATH, "a", encoding="utf-8") as f:
            f.write(json.dumps(row) + "\n")
    except Exception:
        # Never propagate — instrumentation must never break trading.
        pass


def _mins_since(ts_iso: str, default: float = 0.0) -> float:
    """Minutes elapsed since an ISO-UTC timestamp. Tolerant of naive/aware."""
    try:
        dt = datetime.fromisoformat(ts_iso.replace("Z", "+00:00"))
        if dt.tzinfo is None:
            dt = dt.replace(tzinfo=UTC)
        return (datetime.now(UTC) - dt).total_seconds() / 60
    except Exception:
        return default


# Sentinel for "use module default" in _evaluate_stop_exits kwargs.
# Distinct from None, because None for trail_stop_pct means "trailing disabled."
_USE_MODULE_DEFAULT: object = object()


def _evaluate_stop_exits(
    pnl_pct: float,
    peak_pct: float,
    current_price: float,
    peak_price: float,
    *,
    stop_loss_pct: float | object = _USE_MODULE_DEFAULT,
    trail_activate_pct: float | object = _USE_MODULE_DEFAULT,
    trail_stop_pct: float | None | object = _USE_MODULE_DEFAULT,
    trail_min_pnl_pct: float | object = _USE_MODULE_DEFAULT,
) -> str | None:
    """Sprint 7 (2026-05-27 autopsy) — pure exit-decision helper.

    Returns ``"stop_loss"`` / ``"trailing_stop"`` / ``None``.

    Order matters: stop_loss is the hard floor and is checked FIRST so a
    poll-gap drop that satisfies both stop_loss AND trailing is correctly
    recorded as stop_loss (not trailing_stop). Trailing has an additional
    safety guard requiring ``pnl_pct > trail_min_pnl_pct`` — if pnl has
    already breached the trail-min-floor (default -1%) when the retrace
    condition fires, the trailing branch declines and the position falls
    through to the stop_loss check or stays open until the next poll.

    This fixes the bot-honesty Fix 1 + Sprint 6 Phase A finding: trailing_stop
    mean was -2.12% with one disaster at -6.28% (poll-gap slippage). Post-fix,
    trailing_stop is bounded to pnl ∈ (-1%, +∞); -3% to -6% bleed-throughs
    get labeled stop_loss and capped at -STOP_LOSS_PCT.

    All thresholds are kwarg-defaulted to the module constants so tests can
    pin values without touching module state. None of the kwargs mutates
    anything; this function is pure and side-effect-free.
    """
    sl = STOP_LOSS_PCT if stop_loss_pct is _USE_MODULE_DEFAULT else stop_loss_pct
    ta = (
        TRAIL_ACTIVATE_AFTER_PCT
        if trail_activate_pct is _USE_MODULE_DEFAULT
        else trail_activate_pct
    )
    ts = TRAIL_STOP_PCT if trail_stop_pct is _USE_MODULE_DEFAULT else trail_stop_pct
    tm = TRAIL_MIN_PNL_PCT if trail_min_pnl_pct is _USE_MODULE_DEFAULT else trail_min_pnl_pct

    # Stop-loss wins over everything. Eval order is the load-bearing fix.
    if pnl_pct <= -sl:
        return "stop_loss"

    # Trailing only fires if (a) trail is configured, (b) peak ever cleared
    # the activation gate, (c) current price retraced >= trail_stop_pct from
    # peak, AND (d) pnl is still above the trail safety floor.
    if ts is not None and peak_price > 0 and peak_pct >= ta:
        trail_retrace_pct = (peak_price - current_price) / peak_price * 100
        if trail_retrace_pct >= ts and pnl_pct > tm:
            return "trailing_stop"

    return None


# ── Monitor open positions ─────────────────────────────────────────
def monitor_positions() -> None:
    for pos in [p for p in positions if p["status"] == "open"]:
        price_data = _get_oc().get_price_info(pos["token"])
        current_price = _spot_from_price_response(price_data)
        if not current_price:
            continue

        # Track last new-high time BEFORE updating peak, so we can tell
        # whether THIS poll set a new high (used by the flat-stall gate).
        prev_peak = pos.get("peak_price", 0)
        now_iso = datetime.now(UTC).isoformat()
        if current_price >= prev_peak:
            pos["last_new_high_ts"] = now_iso
        elif "last_new_high_ts" not in pos:
            # Positions recovered from state pre-iter-3.8 won't have it —
            # seed from entry so the no-new-high timer starts at entry.
            pos["last_new_high_ts"] = pos.get("entry_ts", now_iso)

        pos["peak_price"] = max(prev_peak, current_price)
        ep = pos["entry_price"]
        pnl_pct = (current_price - ep) / ep * 100 if ep else 0.0
        peak_pct = (pos["peak_price"] - ep) / ep * 100 if ep else 0.0
        mins_since_high = _mins_since(pos["last_new_high_ts"])

        # Telemetry — one row per position per poll (data foundation for v2).
        _log_telemetry(
            {
                "ts": now_iso,
                "symbol": pos.get("symbol"),
                "token": pos.get("token"),
                "price": current_price,
                "entry_price": ep,
                "pnl_pct": round(pnl_pct, 4),
                "peak_pct": round(peak_pct, 4),
                "mins_since_high": round(mins_since_high, 2),
                "age_min": round(_mins_since(pos.get("entry_ts", now_iso)), 2),
                "mode": pos.get("mode"),
            }
        )

        # Stop-loss + trailing-stop are evaluated together by the Sprint 7
        # pure helper (2026-05-27). Stop-loss is checked FIRST so a poll-gap
        # drop that satisfies both is recorded as stop_loss (not trailing).
        # Trailing has a safety guard: pnl_pct must stay above
        # TRAIL_MIN_PNL_PCT for the trailing branch to fire — otherwise the
        # position falls through to stop_loss on this or the next poll.
        # See _evaluate_stop_exits docstring for full rationale + autopsy ref.
        stop_exit_reason = _evaluate_stop_exits(
            pnl_pct=pnl_pct,
            peak_pct=peak_pct,
            current_price=current_price,
            peak_price=pos["peak_price"],
        )
        if stop_exit_reason:
            close_position(pos, stop_exit_reason, current_price)
            continue

        # Tiered take profit

        # Flat take profit (adaptive per-position TP; fallback to fixed for old positions)
        if pnl_pct >= pos.get("tp_pct", TAKE_PROFIT_PCT):
            close_position(pos, "take_profit", current_price)
            continue

        # iter-3.5 stall-green exit (founder rule, 2026-05-20):
        # If position has been open ≥60min AND is green by ≥2%, book the win
        # rather than waiting indefinitely for TP. Catches the modal failure
        # mode where price drifts to +2-3% then stalls — neither trail (no
        # retracement) nor TP (never hits 4%) fire, and the position bleeds
        # the 12h time-stop near $0.
        entry_ts_iso = pos.get("entry_ts", "")
        try:
            entry_dt = datetime.fromisoformat(entry_ts_iso.replace("Z", "+00:00"))
            if entry_dt.tzinfo is None:
                entry_dt = entry_dt.replace(tzinfo=UTC)
            age_min = (datetime.now(UTC) - entry_dt).total_seconds() / 60
        except Exception:
            age_min = 0.0
        if age_min >= STALL_GREEN_EXIT_AGE_MIN and pnl_pct >= STALL_GREEN_EXIT_MIN_PCT:
            close_position(pos, "stall_green_exit", current_price)
            continue

        # iter-3.8 flat-stall exit (see constants block). Catches the BONK
        # no-man's-land BELOW the +2% stall_green_exit threshold: aged,
        # stuck in the +0.3-2% band, and no new high in 30min (= momentum
        # spent, not consolidating). Locks the small green before it drifts
        # to a flat/negative 12h time-stop.
        #
        # Sprint 24-Q (2026-05-31) — fee-aware variant when env-gated:
        # exit only if pnl clears the fee floor (default +0.5%) OR drops
        # past the cut-loss floor (default -1.0%); else HOLD. Closes the
        # "we sell tiny wins into fee-erosion" leak the founder flagged.
        age_qualified = age_min >= FLAT_STALL_AGE_MIN
        stalled = mins_since_high >= FLAT_STALL_NO_NEW_HIGH_MIN
        if FLAT_STALL_FEE_AWARE:
            in_exit_band = pnl_pct >= FLAT_STALL_MIN_EXIT_PCT or pnl_pct <= -FLAT_STALL_MAX_LOSS_PCT
        else:
            in_exit_band = FLAT_STALL_PNL_LO <= pnl_pct <= FLAT_STALL_PNL_HI
        if age_qualified and in_exit_band and stalled:
            close_position(pos, "flat_stall_exit", current_price)
            continue

        print(
            f"[POS] {pos['symbol'] or pos['token'][:12]} | ${ep:.6f} → ${current_price:.6f} | {pnl_pct:+.1f}%"
        )


# ── Risk guards ────────────────────────────────────────────────────
def reset_daily() -> None:
    global daily_trades, last_reset_day
    today = datetime.utcnow().strftime("%Y-%m-%d")
    if today != last_reset_day:
        daily_trades = 0
        last_reset_day = today
        _persist_state()


def should_pause() -> bool:
    if consec_losses >= SESSION_LOSS_PAUSE:
        print(f"[PAUSE] {consec_losses} consecutive losses — sitting out this session")
        return True
    return False


# ── Main loop ──────────────────────────────────────────────────────
def main() -> None:
    ap = argparse.ArgumentParser()
    ap.add_argument(
        "--smoke-test", action="store_true", help="Verify dashboard endpoints then exit"
    )
    ap.add_argument(
        "--rebuild-state",
        action="store_true",
        help="Force rebuild of bot_state from today's artifact log (bypasses bot_state.json).",
    )
    args = ap.parse_args()

    print(f"""
╔══════════════════════════════════════╗
║  My Strategy                          ║
║                                       ║
╠══════════════════════════════════════╣
║  Mode   : {"PAPER 📄" if PAPER_TRADE else "LIVE  🔴":<29} ║
║  Obs    : {"ON — entries gated off" if OBSERVATION_MODE else "OFF — entries armed":<29} ║
║  Entry  : {ENTRY_TYPE:<29} ║
║  SL -{STOP_LOSS_PCT}%  TP +{TAKE_PROFIT_PCT}%                      ║
╚══════════════════════════════════════╝
""")

    if args.smoke_test:
        import urllib.request as _ureq

        _start_dashboard()
        time.sleep(1.5)
        try:
            r1 = _ureq.urlopen(f"http://localhost:{DASHBOARD_PORT}/", timeout=4)
            assert r1.status == 200, f"/ returned {r1.status}"
            r2 = _ureq.urlopen(f"http://localhost:{DASHBOARD_PORT}/api/state", timeout=4)
            assert r2.status == 200, f"/api/state returned {r2.status}"
            json.loads(r2.read())  # must be valid JSON
            print("SMOKE_TEST_OK")
            sys.exit(0)
        except Exception as e:
            print(f"SMOKE_TEST_FAIL: {e}")
            sys.exit(1)

    if not preflight():
        sys.exit(1)

    # ── Live mode gate ─────────────────────────────────────────────
    if not PAPER_TRADE:
        print("\n" + "=" * 50)
        print("🔴  LIVE MODE — REAL FUNDS AT RISK")
        print("=" * 50)
        print("  Strategy   : My Strategy")
        print(f"  Per trade  : ${USD_PER_TRADE} USD")
        print(f"  Budget cap : ${MAX_BUDGET_USD} USD")
        print(f"  Stop loss  : -{STOP_LOSS_PCT}%")
        print("\nReal money will be used. Losses are permanent.")
        print("Safety filters do not guarantee protection against all fraud.")
        print("Automated trading may generate significant taxable events.")
        print("\nType CONFIRM to proceed, or press Ctrl+C to cancel:\n")
        try:
            user_input = input("> ").strip()
        except (KeyboardInterrupt, EOFError):
            print("\nCancelled. Run with PAPER_TRADE = True to test first.")
            sys.exit(0)
        if user_input.upper() != "CONFIRM":
            print("\nLive mode not activated. Set PAPER_TRADE = True to run in paper mode.")
            sys.exit(0)
        # Log acknowledgment
        import json as _json

        _ack = {
            "ts": datetime.utcnow().isoformat(),
            "strategy": "jto_breakout_gecko_gated_contest",
            "confirmation": "CONFIRM",
            "budget_cap": MAX_BUDGET_USD,
        }
        _ack_path = _STATE_BASE / "jto_breakout_gecko_gated_contest_live_ack.jsonl"
        with open(_ack_path, "a") as _f:
            _f.write(_json.dumps(_ack) + "\n")
        print("\n✅ Live mode confirmed. Starting bot...\n")

    _start_dashboard()

    # ── Fundamentals preload (s40-lab-#7) ──────────────────────────
    # Fire ~80-100s of parallel PRD calls before the trade loop starts.
    # Failures degrade gracefully — bot still runs without the cached
    # side notes. SKIP if the env var is set (smoke tests, dev runs).
    if not os.environ.get("GECKO_FUND_PRELOAD_SKIP"):
        print(
            f"[fundamentals] preloading verdicts for {len(INSTRUMENTS)} "
            f"instruments (parallel, ~80-100s)..."
        )
        try:
            _cache = asyncio.run(_FUNDAMENTALS.preload_for_instruments(INSTRUMENTS))
            print(f"[fundamentals] preloaded {len(_cache)} verdicts")
            for _sym, _v in _cache.items():
                print(f"  {_sym:6s}: {_v.verdict}@{_v.confidence:.2f}  {_v.citations_count} cites")
                # Surface preloaded verdicts in the studio Oracle panel immediately.
                _LAST_FUND[_sym] = _fund_snapshot(_v)
        except Exception as _exc:
            print(f"[fundamentals] preload failed (degraded mode): {_exc}")
    else:
        print("[fundamentals] preload skipped (GECKO_FUND_PRELOAD_SKIP set)")

    print(f"Scanning every {POLL_SEC}s — Ctrl+C to stop\n")

    try:
        while True:
            # S0-4: heartbeat MUST be first — a hung iteration leaves a
            # detectable gap. The function is best-effort (failures print
            # but never raise) so a transient disk error never crashes the
            # trading loop.
            _record_heartbeat()
            # S0-5: detect logical state from existing pause conditions
            # (breaker / consec-losses) and emit state_transition events
            # on changes; check dwell-time SLOs and emit alerts on overrun.
            # Both BEFORE the early-continue so paused states are tracked.
            _detect_state_and_transition()
            _check_dwell_slo()
            reset_daily()
            if should_pause():
                time.sleep(POLL_SEC * 2)
                continue

            monitor_positions()
            poll_instruments()
            time.sleep(POLL_SEC)

    except KeyboardInterrupt:
        closed = [p for p in positions if p["status"] == "closed"]
        open_pos = sum(1 for p in positions if p["status"] == "open")
        total_pnl = sum(p.get("pnl_usd", 0) for p in closed)
        wins = sum(1 for p in closed if p.get("pnl_usd", 0) > 0)
        print("\n👋 Bot stopped.")
        print(f"   {len(closed)} trades | {wins}W / {len(closed) - wins}L | PnL: ${total_pnl:+.2f}")
        if open_pos:
            print(f"   ⚠️  {open_pos} position(s) still open — close manually if live")


if __name__ == "__main__":
    main()
